-- Rung — GLOBAL CONTENT (tracks + rungs) as the source of truth, fetched by
-- the app and cached into local SQLite (offline-first). Run AFTER 0001-0006.
-- 6 tracks x 40 rungs. Tier gating (free 5 / monthly 30 / yearly 40 per track)
-- is applied client-side over this set. Read-only to clients; edit here to
-- change challenges without an app release (bump updated_at to push edits).

create table if not exists public.content_tracks (
  id          text primary key,
  slug        text not null,
  title       text not null,
  description text not null,
  icon        text not null,
  sort_order  int  not null,
  color_seed  text not null
);

create table if not exists public.content_rungs (
  id           text primary key,
  track_id     text not null references public.content_tracks (id),
  title        text not null,
  what_to_do   text not null,
  why_it_helps text not null,
  difficulty   int  not null,
  sort_order   int  not null,
  est_minutes  int  not null default 2,
  updated_at   bigint not null default 0,
  deleted_at   bigint
);
create index if not exists idx_content_rungs_track
  on public.content_rungs (track_id, sort_order);

alter table public.content_tracks enable row level security;
alter table public.content_rungs  enable row level security;
-- Content is global and read-only to clients (managed here in SQL/dashboard).
drop policy if exists content_tracks_read on public.content_tracks;
create policy content_tracks_read on public.content_tracks for select using (true);
drop policy if exists content_rungs_read on public.content_rungs;
create policy content_rungs_read on public.content_rungs for select using (true);

on conflict (id) do update set
  slug=excluded.slug, title=excluded.title, description=excluded.description,
  icon=excluded.icon, sort_order=excluded.sort_order, color_seed=excluded.color_seed;

on conflict (id) do update set
  track_id=excluded.track_id, title=excluded.title, what_to_do=excluded.what_to_do,
  why_it_helps=excluded.why_it_helps, difficulty=excluded.difficulty,
  sort_order=excluded.sort_order, est_minutes=excluded.est_minutes,
  updated_at=excluded.updated_at, deleted_at=excluded.deleted_at;
