insert into public.content_tracks (id, slug, title, description, icon, sort_order, color_seed) values
  ('trk_speaking', 'speaking', 'Speaking up', 'Speaking & being the center of attention', 'mic', 1, 'indigo'),
  ('trk_approaching', 'approaching', 'Approaching people', 'Meeting & approaching people', 'wave', 2, 'teal'),
  ('trk_social_events', 'social_events', 'Social events', 'Group & social events', 'groups', 3, 'violet'),
  ('trk_assertiveness', 'assertiveness', 'Assertiveness', 'Conflict & assertiveness', 'balance', 4, 'rose'),
  ('trk_visibility', 'visibility', 'Being visible', 'Visibility & being judged', 'visibility', 5, 'amber'),
  ('trk_pressure', 'pressure', 'Under pressure', 'Performance under social pressure', 'bolt', 6, 'sky')
insert into public.content_rungs (id, track_id, title, what_to_do, why_it_helps, difficulty, sort_order, est_minutes, updated_at) values
  ('rng_speaking_01', 'trk_speaking', 'Text a question into a group chat', 'Post one genuine question in a group chat you usually just read.', 'Low-stakes visibility warms up the "being seen" muscle.', 1, 1, 2, 0),
  ('rng_speaking_02', 'trk_speaking', 'Ask a cashier or stranger one short question', 'Ask someone working nearby something simple — the time, or where to find something.', 'Proves a quick exchange with a stranger is survivable.', 2, 2, 2, 0),
  ('rng_speaking_03', 'trk_speaking', 'Give one opinion out loud in a casual group', 'Share a small preference or take in a relaxed conversation.', 'Your voice can take up space without anything going wrong.', 3, 3, 3, 0),
  ('rng_speaking_04', 'trk_speaking', 'Ask a question in a meeting or class', 'Raise one clarifying question when you would normally stay quiet.', 'Speaking in a structured room is practice for bigger asks.', 4, 4, 3, 0),
  ('rng_speaking_05', 'trk_speaking', 'Share an update or idea unprompted in a meeting', 'Offer one update or idea before anyone calls on you.', 'Volunteering, not just answering, builds real confidence.', 5, 5, 5, 0),
  ('rng_speaking_06', 'trk_speaking', 'Make a phone call you''d normally avoid', 'Call a shop, clinic, or service for one quick thing.', 'Phone calls remove body language to lean on — good reps.', 6, 6, 5, 0),
  ('rng_speaking_07', 'trk_speaking', 'Raise your hand to answer in front of a room', 'Answer one question with the whole room watching.', 'A brief spotlight, then it passes — your prediction gets tested.', 7, 7, 3, 0),
  ('rng_speaking_08', 'trk_speaking', 'Give a 2-minute explanation to a small group', 'Explain something you know to a few people for a couple of minutes.', 'Sustained attention is a skill that gets easier with reps.', 8, 8, 5, 0),
  ('rng_speaking_09', 'trk_speaking', 'Say a few words at a gathering', 'Propose a toast or say something warm when there is a natural moment.', 'Marking a moment out loud is memorable and very doable.', 9, 9, 5, 0),
  ('rng_speaking_10', 'trk_speaking', 'Give a short prepared presentation', 'Deliver a few prepared minutes to a group.', 'The top rung — proof of how far the ladder has carried you.', 10, 10, 10, 0),
  ('rng_approaching_01', 'trk_approaching', 'Make eye contact and smile at someone', 'Catch a stranger''s eye and offer a small smile.', 'A tiny signal that opening contact is safe.', 1, 1, 1, 0),
  ('rng_approaching_02', 'trk_approaching', 'Greet a neighbor or coworker', 'Offer a ''morning'' or ''how''s it going'' you''d normally skip.', 'Greetings are low-cost reps for initiating.', 2, 2, 1, 0),
  ('rng_approaching_03', 'trk_approaching', 'Give someone a genuine compliment', 'Tell a stranger or acquaintance one true, specific compliment.', 'Warm openers make approaching feel kind, not scary.', 3, 3, 2, 0),
  ('rng_approaching_04', 'trk_approaching', 'Ask a stranger a small favor or question', 'Ask for a recommendation, directions, or a quick hand.', 'People help more often than your fear predicts.', 4, 4, 2, 0),
  ('rng_approaching_05', 'trk_approaching', 'Make small talk in a queue or lift', 'Start a light, throwaway comment with someone nearby.', 'Small talk is a skill — boring topics are perfect practice.', 5, 5, 3, 0),
  ('rng_approaching_06', 'trk_approaching', 'Introduce yourself to someone new', 'Walk up, say your name, and ask theirs.', 'The introduction is the hard part, and it''s over in seconds.', 6, 6, 3, 0),
  ('rng_approaching_07', 'trk_approaching', 'Join an ongoing group conversation', 'Step into a group chat with a question or a point of agreement.', 'Joining feels riskier than it is — they rarely mind.', 7, 7, 4, 0),
  ('rng_approaching_08', 'trk_approaching', 'Swap contacts with someone you just met', 'If a chat goes well, suggest staying in touch.', 'Turning a moment into a connection is its own brave act.', 8, 8, 3, 0),
  ('rng_approaching_09', 'trk_approaching', 'Invite an acquaintance to do something', 'Ask someone you like-but-barely-know to a low-key plan.', 'Initiating plans is how acquaintances become friends.', 9, 9, 5, 0),
  ('rng_approaching_10', 'trk_approaching', 'Start a conversation with someone you find attractive', 'Open a friendly, no-agenda chat with someone you are drawn to.', 'The top rung — high nerves, very survivable, great data.', 10, 10, 5, 0),
  ('rng_social_events_01', 'trk_social_events', 'Say yes to one invitation', 'Accept an invite you''d usually find a reason to decline.', 'Showing up is the whole battle; saying yes starts it.', 1, 1, 1, 0),
  ('rng_social_events_02', 'trk_social_events', 'Walk in and stay 15 minutes', 'Arrive, get a drink, and give yourself a 15-minute floor.', 'A small time goal makes the doorway less daunting.', 2, 2, 15, 0),
  ('rng_social_events_03', 'trk_social_events', 'Stand with a group instead of hiding on your phone', 'Park yourself near or in a group and just be present.', 'Being visibly part of things, even quietly, counts.', 3, 3, 5, 0),
  ('rng_social_events_04', 'trk_social_events', 'Ask one person about themselves', 'Pick one person and ask something curious about them.', 'Curiosity takes the spotlight off you and fills silences.', 4, 4, 3, 0),
  ('rng_social_events_05', 'trk_social_events', 'Stay at an event for an hour', 'Set an hour goal and let yourself leave after.', 'Tolerating the time builds evidence you can handle it.', 5, 5, 60, 0),
  ('rng_social_events_06', 'trk_social_events', 'Introduce two people to each other', 'Connect two people who don''t know each other yet.', 'Playing host gives you a role and eases self-focus.', 6, 6, 3, 0),
  ('rng_social_events_07', 'trk_social_events', 'Go where you know almost no one', 'Attend something with mostly unfamiliar faces.', 'Fewer safety blankets, bigger growth in the same loop.', 7, 7, 30, 0),
  ('rng_social_events_08', 'trk_social_events', 'Share a story with a small group', 'Tell a short anecdote when the conversation opens up.', 'Holding a group''s attention briefly is a real milestone.', 8, 8, 5, 0),
  ('rng_social_events_09', 'trk_social_events', 'Attend an event alone', 'Go to something on your own, with no buddy to lean on.', 'Solo attendance proves you can self-rescue and stay.', 9, 9, 30, 0),
  ('rng_social_events_10', 'trk_social_events', 'Host a small get-together', 'Invite a few people and run a simple plan.', 'The top rung — you become the reason others gather.', 10, 10, 60, 0),
  ('rng_assertiveness_01', 'trk_assertiveness', 'Say "no thanks" to a small offer', 'Decline a free sample, an upsell, or a small offer cleanly.', 'A calm ''no'' to something tiny rehearses bigger boundaries.', 1, 1, 1, 0),
  ('rng_assertiveness_02', 'trk_assertiveness', 'Ask to fix a small order mistake', 'Point out a wrong order and ask for it to be put right.', 'You are allowed to get what you actually paid for.', 2, 2, 2, 0),
  ('rng_assertiveness_03', 'trk_assertiveness', 'Express a different preference', 'Say what you''d actually prefer instead of ''I don''t mind''.', 'Your preferences are valid data other people can use.', 3, 3, 2, 0),
  ('rng_assertiveness_04', 'trk_assertiveness', 'Ask a friend for a small favor', 'Ask someone you trust for a minor bit of help.', 'Asking isn''t a burden — it''s how closeness works.', 4, 4, 2, 0),
  ('rng_assertiveness_05', 'trk_assertiveness', 'Politely disagree out loud', 'Voice a different view on something that doesn''t matter much.', 'Disagreeing kindly shows conflict needn''t be a rupture.', 5, 5, 3, 0),
  ('rng_assertiveness_06', 'trk_assertiveness', 'Return an item or ask for a refund', 'Bring something back and request a refund or exchange.', 'A clear, polite request usually just works.', 6, 6, 5, 0),
  ('rng_assertiveness_07', 'trk_assertiveness', 'Set a boundary with someone', 'Decline a real request that would overextend you.', 'Boundaries protect the energy you give to people you love.', 7, 7, 3, 0),
  ('rng_assertiveness_08', 'trk_assertiveness', 'Give honest constructive feedback', 'Offer one kind, specific piece of feedback someone can use.', 'Honest care, delivered gently, deepens trust.', 8, 8, 5, 0),
  ('rng_assertiveness_09', 'trk_assertiveness', 'Address a recurring issue directly', 'Name an ongoing problem calmly with the person involved.', 'Naming it once beats resenting it quietly for months.', 9, 9, 10, 0),
  ('rng_assertiveness_10', 'trk_assertiveness', 'Negotiate something significant', 'Make a prepared case for a raise or something that matters.', 'The top rung — advocacy for yourself, with real stakes.', 10, 10, 15, 0),
  ('rng_visibility_01', 'trk_visibility', 'Post something small and personal online', 'Share one genuine photo, thought, or update publicly.', 'Being mildly visible online rehearses being seen.', 1, 1, 2, 0),
  ('rng_visibility_02', 'trk_visibility', 'Wear something that draws a little attention', 'Wear a color, item, or style slightly bolder than usual.', 'Small visible choices prove eyes on you are harmless.', 2, 2, 2, 0),
  ('rng_visibility_03', 'trk_visibility', 'Eat or sit alone in a public place', 'Spend time solo somewhere public, unhurried.', 'Nobody is watching as closely as the fear insists.', 3, 3, 15, 0),
  ('rng_visibility_04', 'trk_visibility', 'Ask a question in front of others', 'Ask something publicly that briefly puts eyes on you.', 'A short spotlight, then attention moves on.', 4, 4, 2, 0),
  ('rng_visibility_05', 'trk_visibility', 'Share your work or hobby with someone', 'Show one thing you''ve made or care about to a person.', 'Letting people see your effort is a vulnerable, good rep.', 5, 5, 5, 0),
  ('rng_visibility_06', 'trk_visibility', 'Take a compliment without deflecting', 'Receive praise with a simple ''thank you'' and nothing else.', 'Letting praise land is its own form of being seen.', 6, 6, 1, 0),
  ('rng_visibility_07', 'trk_visibility', 'Speak up about a mistake you made', 'Own a small error out loud instead of hiding it.', 'Visible imperfection rarely costs what you fear.', 7, 7, 3, 0),
  ('rng_visibility_08', 'trk_visibility', 'Post a video or voice note of yourself', 'Share something with your face or voice in it.', 'Your real presence on display is a meaningful step.', 8, 8, 5, 0),
  ('rng_visibility_09', 'trk_visibility', 'Share an opinion that may get pushback', 'Say something honest that not everyone will love.', 'Tolerating disagreement is freedom from needing approval.', 9, 9, 5, 0),
  ('rng_visibility_10', 'trk_visibility', 'Perform or present where you are the focus', 'Put yourself center-stage in front of an audience.', 'The top rung — fully seen, and still standing.', 10, 10, 10, 0),
  ('rng_pressure_01', 'trk_pressure', 'Decide quickly while someone waits', 'Choose at the counter without over-apologizing for the pause.', 'Small time pressure, handled, shrinks the dread of it.', 1, 1, 1, 0),
  ('rng_pressure_02', 'trk_pressure', 'Answer an unexpected question on the spot', 'Give a real answer when caught off guard, even imperfectly.', '''Good enough, right now'' beats a perfect answer too late.', 2, 2, 1, 0),
  ('rng_pressure_03', 'trk_pressure', 'Speak while a few people watch you work', 'Talk through what you are doing with an audience of a few.', 'Performing and explaining at once gets smoother with reps.', 3, 3, 3, 0),
  ('rng_pressure_04', 'trk_pressure', 'Do a task with someone observing', 'Do something ordinary while someone watches, without rushing.', 'Being observed is uncomfortable, not dangerous.', 4, 4, 3, 0),
  ('rng_pressure_05', 'trk_pressure', 'Think out loud in front of others', 'Work through a problem verbally instead of going silent.', 'Showing your reasoning, messy and all, builds trust.', 5, 5, 5, 0),
  ('rng_pressure_06', 'trk_pressure', 'Lead a small group decision', 'Propose the plan and help the group choose quickly.', 'Light leadership under mild pressure is a powerful rep.', 6, 6, 5, 0),
  ('rng_pressure_07', 'trk_pressure', 'Give an answer you''re unsure about, confidently', 'Offer your best guess clearly, flagging it as a guess.', 'Calibrated confidence is more useful than silence.', 7, 7, 3, 0),
  ('rng_pressure_08', 'trk_pressure', 'Field questions after sharing something', 'Invite and answer a couple of questions on the spot.', 'Live Q&A is unscripted pressure — and very learnable.', 8, 8, 5, 0),
  ('rng_pressure_09', 'trk_pressure', 'Improvise when a plan changes last-minute', 'Adapt out loud when something goes off-script.', 'Flexibility under pressure is a skill, not a personality.', 9, 9, 5, 0),
  ('rng_pressure_10', 'trk_pressure', 'Take on a timed, watched, high-stakes task', 'Take on something with a clock and an audience.', 'The top rung — pressure, eyes, stakes, and you handling it.', 10, 10, 15, 0),
  ('rng_speaking_11', 'trk_speaking', 'Ask a follow-up question in a meeting', 'After someone shares an idea in a meeting or class, ask them one clarifying question out loud.', 'Building on others'' words keeps the focus shared, so speaking up feels lighter.', 5, 11, 5, 0),
  ('rng_speaking_12', 'trk_speaking', 'Tell a short story to a small group', 'Share a brief personal story or something funny that happened to you with a few people.', 'Holding attention for a moment shows you that eyes on you can feel warm, not scary.', 5, 12, 10, 0),
  ('rng_speaking_13', 'trk_speaking', 'Disagree politely with one point', 'In a casual chat, gently say you see something differently and explain why in a sentence.', 'Voicing a different view, kindly, proves your opinion can take up space safely.', 6, 13, 5, 0),
  ('rng_speaking_14', 'trk_speaking', 'Introduce yourself to a new group', 'Say your name and a line about yourself to a group of people you''ve just joined.', 'A short introduction is a tiny spotlight that gets easier each time you step into it.', 6, 14, 10, 0),
  ('rng_speaking_15', 'trk_speaking', 'Ask a question at a public event', 'At a talk, workshop, or Q&A, raise your hand and ask the speaker one question.', 'Speaking to a room of strangers once shows you the moment passes quickly and kindly.', 6, 15, 15, 0),
  ('rng_speaking_16', 'trk_speaking', 'Lead a short part of a meeting', 'Volunteer to run one small agenda item or update while others listen.', 'Holding the floor on purpose builds quiet confidence in your own voice.', 7, 16, 15, 0),
  ('rng_speaking_17', 'trk_speaking', 'Give a toast or thank-you out loud', 'At a meal or small gathering, stand or speak up to thank or toast someone.', 'Warm words shared aloud remind you that attention can feel generous and kind.', 7, 17, 10, 0),
  ('rng_speaking_18', 'trk_speaking', 'Speak up to someone in authority', 'Raise one question or point with a manager, teacher, or official, calmly and clearly.', 'Using your voice with someone senior shows you that you belong in the conversation.', 7, 18, 20, 0),
  ('rng_speaking_19', 'trk_speaking', 'Record a short voice message', 'Send a 30-second voice note sharing a thought, instead of typing it out.', 'Hearing your own voice land well softens the worry about how you sound.', 7, 19, 15, 0),
  ('rng_speaking_20', 'trk_speaking', 'Answer an unexpected question on the spot', 'When asked something you didn''t prepare for, take a breath and give a short answer aloud.', 'Speaking without a script shows you that you can trust yourself in the moment.', 7, 20, 20, 0),
  ('rng_speaking_21', 'trk_speaking', 'Speak up on a video call with cameras on', 'On a video call, turn your camera on and share at least one full point.', 'Being seen and heard at once is a stretch that gets gentler with each call.', 8, 21, 15, 0),
  ('rng_speaking_22', 'trk_speaking', 'Lead a small group discussion', 'Guide a few people through a topic, inviting their views and keeping things moving.', 'Steering a conversation shows you can hold a room with calm, not control.', 8, 22, 20, 0),
  ('rng_speaking_23', 'trk_speaking', 'Give a 5-minute talk to a group', 'Prepare and deliver a five-minute talk on something you know to a small audience.', 'A longer talk proves you can stay steady well past the first nervous minute.', 8, 23, 30, 0),
  ('rng_speaking_24', 'trk_speaking', 'Share an unpopular idea in a group', 'Offer a view you suspect others may not share, said calmly and without apology.', 'Standing gently behind your own thinking builds a sturdier sense of self.', 8, 24, 15, 0),
  ('rng_speaking_25', 'trk_speaking', 'Make a phone call to sort out a problem', 'Call to question a bill, fix a booking, or resolve an issue you''d rather avoid.', 'Handling a tricky call shows you can speak up even when something''s at stake.', 8, 25, 20, 0),
  ('rng_speaking_26', 'trk_speaking', 'Tell a joke or light story to a room', 'Share something amusing with a larger group and let yourself enjoy the pause.', 'Inviting a laugh shows you that being the center of attention can be fun.', 8, 26, 15, 0),
  ('rng_speaking_27', 'trk_speaking', 'Ask a question at a large gathering', 'In a room of many people, speak up so everyone can hear and ask your question.', 'Letting your voice carry across a big space shows you can take up real space.', 9, 27, 20, 0),
  ('rng_speaking_28', 'trk_speaking', 'Run a meeting from start to finish', 'Chair a full meeting, opening it, guiding each item, and closing it out.', 'Holding the whole room for a while builds deep trust in your own steadiness.', 9, 28, 30, 0),
  ('rng_speaking_29', 'trk_speaking', 'Give live feedback to a group', 'Offer honest, kind feedback aloud while the people involved are listening.', 'Speaking truth gently in real time shows your voice can carry care and weight.', 9, 29, 20, 0),
  ('rng_speaking_30', 'trk_speaking', 'Record a video of yourself talking', 'Film a short clip of yourself speaking to camera about a topic you care about.', 'Seeing yourself on screen, kindly, loosens the grip of worrying how you appear.', 9, 30, 30, 0),
  ('rng_speaking_31', 'trk_speaking', 'Give an impromptu 2-minute talk', 'Pick a topic with little notice and speak about it for two minutes to a group.', 'Talking off the cuff shows you that you have more to say than you expect.', 9, 31, 20, 0),
  ('rng_speaking_32', 'trk_speaking', 'Speak on a panel or as one of several', 'Take a seat on a panel or shared stage and answer questions in front of others.', 'Sharing a spotlight teaches you to stay present even with eyes coming and going.', 9, 32, 30, 0),
  ('rng_speaking_33', 'trk_speaking', 'Raise a difficult topic with a group', 'Bring up a sensitive or awkward subject the group has been avoiding, calmly.', 'Naming the hard thing out loud shows your voice can hold real moments well.', 9, 33, 25, 0),
  ('rng_speaking_34', 'trk_speaking', 'Teach or demonstrate something to a group', 'Lead a short lesson or how-to, taking questions as you go.', 'Guiding others through your knowledge shows attention can sit on you with ease.', 9, 34, 30, 0),
  ('rng_speaking_35', 'trk_speaking', 'Give a 15-minute presentation', 'Prepare and deliver a fifteen-minute talk, with slides or notes, to an audience.', 'A longer presentation shows you can carry a room for the long stretch, calmly.', 10, 35, 40, 0),
  ('rng_speaking_36', 'trk_speaking', 'Go live on video to an audience', 'Stream or broadcast yourself speaking live to people watching in real time.', 'Speaking live shows you can be present and seen without needing a second take.', 10, 36, 30, 0),
  ('rng_speaking_37', 'trk_speaking', 'Handle tough questions after you speak', 'After a talk, open the floor and answer challenging questions on the spot.', 'Staying steady under questions shows you can hold your ground with grace.', 10, 37, 30, 0),
  ('rng_speaking_38', 'trk_speaking', 'Speak up to a large group in authority', 'Raise a point or concern before a board, council, or full leadership audience.', 'Voicing yourself at the highest table shows just how far your courage has grown.', 10, 38, 30, 0),
  ('rng_speaking_39', 'trk_speaking', 'Give a personal or emotional speech', 'Deliver heartfelt words at a celebration or event where the moment matters deeply.', 'Letting feeling and voice meet in front of others is a quiet, powerful win.', 10, 39, 40, 0),
  ('rng_speaking_40', 'trk_speaking', 'Give a talk to a large audience', 'Speak from a stage or front of a hall to a sizeable crowd for several minutes.', 'Standing before many and finding your voice shows how strong you''ve truly become.', 10, 40, 45, 0),
  ('rng_approaching_11', 'trk_approaching', 'Ask a follow-up question to keep a chat going', 'In a casual conversation, ask one curious follow-up question about something the other person just said.', 'Curiosity carries the chat for you, so you don''t have to fill every silence.', 5, 11, 5, 0),
  ('rng_approaching_12', 'trk_approaching', 'Share one personal detail with someone new', 'During a friendly conversation, offer a small fact about yourself, like a hobby or where you grew up.', 'Sharing a little of yourself invites others to open up too.', 5, 12, 5, 0),
  ('rng_approaching_13', 'trk_approaching', 'Comment on something in a shared space', 'Notice something around you and say a light comment about it to a person nearby.', 'The world around you is full of easy, low-stakes openers.', 5, 13, 10, 0),
  ('rng_approaching_14', 'trk_approaching', 'Reconnect with someone you''ve lost touch with', 'Send a short, friendly message to someone you haven''t spoken to in a while just to say hello.', 'Most people are quietly happy to hear from someone who thought of them.', 6, 14, 10, 0),
  ('rng_approaching_15', 'trk_approaching', 'Ask someone about their day and really listen', 'Ask a coworker or acquaintance how their day is going, and give them your full attention.', 'Genuine attention is rare and makes people glad they spoke with you.', 6, 15, 10, 0),
  ('rng_approaching_16', 'trk_approaching', 'Strike up a chat with someone at an event', 'At a gathering or class, turn to someone nearby and start a short conversation.', 'Everyone there came hoping to connect, so you''re meeting them halfway.', 6, 16, 15, 0),
  ('rng_approaching_17', 'trk_approaching', 'Remember and use someone''s name later', 'When you meet someone, hold onto their name and use it next time you see them.', 'Hearing their own name tells people they truly registered with you.', 6, 17, 10, 0),
  ('rng_approaching_18', 'trk_approaching', 'Ask a new acquaintance to grab a coffee', 'Suggest meeting up for a quick coffee or walk to someone you''ve recently met.', 'A small, easy plan is how casual contacts slowly become friends.', 7, 18, 15, 0),
  ('rng_approaching_19', 'trk_approaching', 'Approach a small group and say hello', 'Walk up to a group of two or three people, greet them, and introduce yourself.', 'Groups feel bigger than they are, and a simple hello is always enough to begin.', 7, 19, 15, 0),
  ('rng_approaching_20', 'trk_approaching', 'Find common ground with someone different from you', 'Chat with someone unlike you and search for one shared interest or experience.', 'Common ground is almost always there once you start looking for it.', 7, 20, 15, 0),
  ('rng_approaching_21', 'trk_approaching', 'Keep a conversation going for five minutes', 'Aim to sustain a friendly chat with someone for about five minutes before it ends.', 'Conversations flow more easily once you give them a little room to grow.', 7, 21, 20, 0),
  ('rng_approaching_22', 'trk_approaching', 'Introduce two people to each other', 'Bring two people you know together and introduce them with a friendly note about each.', 'Connecting others takes the spotlight off you and feels genuinely good.', 7, 22, 15, 0),
  ('rng_approaching_23', 'trk_approaching', 'Talk with someone more senior than you', 'Start a short, friendly conversation with a manager, mentor, or respected person.', 'People you admire are usually warmer up close than they seem from afar.', 8, 23, 20, 0),
  ('rng_approaching_24', 'trk_approaching', 'Introduce yourself at a networking event', 'At a professional gathering, approach someone new and share your name and what you do.', 'Everyone in the room is there to meet people, including you.', 8, 24, 20, 0),
  ('rng_approaching_25', 'trk_approaching', 'Ask someone for their advice or expertise', 'Approach someone knowledgeable and ask them a genuine question in their area.', 'Most people enjoy sharing what they know and feel flattered to be asked.', 8, 25, 15, 0),
  ('rng_approaching_26', 'trk_approaching', 'Suggest a concrete plan with a day and time', 'Invite someone to do something and offer a specific day and time to meet.', 'A clear plan is far easier to say yes to than a vague maybe.', 8, 26, 20, 0),
  ('rng_approaching_27', 'trk_approaching', 'Rejoin a group you drifted away from', 'Reach out to a circle or community you''ve fallen out of and show up again.', 'Doors you thought had closed are usually still open and welcoming.', 8, 27, 20, 0),
  ('rng_approaching_28', 'trk_approaching', 'Steer a conversation toward a deeper topic', 'In a chat, gently move past small talk by asking what someone cares about or is excited by.', 'A single real question can turn a polite chat into a real connection.', 8, 28, 25, 0),
  ('rng_approaching_29', 'trk_approaching', 'Approach someone you''d like to date', 'Start a warm, genuine conversation with someone you''re romantically interested in.', 'The first hello is the bravest part, and you''ve already practiced it many times.', 9, 29, 20, 0),
  ('rng_approaching_30', 'trk_approaching', 'Ask someone for their number to stay in touch', 'When a conversation goes well, ask the person if you can swap numbers to continue it.', 'Wanting to keep talking is a compliment, and most people receive it gladly.', 9, 30, 15, 0),
  ('rng_approaching_31', 'trk_approaching', 'Invite someone you''re interested in on a date', 'Ask someone you like to do a specific, low-pressure activity together.', 'A clear, kind invitation is brave no matter the answer, and you can be proud of it.', 9, 31, 20, 0),
  ('rng_approaching_32', 'trk_approaching', 'Speak up and share your view in a group', 'In a group conversation, offer your honest opinion on what''s being discussed.', 'Your perspective adds something only you can bring to the room.', 9, 32, 25, 0),
  ('rng_approaching_33', 'trk_approaching', 'Host a small get-together', 'Invite a few people to gather for coffee, a meal, or a casual hangout you organize.', 'Bringing people together makes you the warm center others are glad to join.', 9, 33, 30, 0),
  ('rng_approaching_34', 'trk_approaching', 'Approach a whole table or busy group', 'Walk up to a lively table or large group, greet them, and join the conversation.', 'Busy groups have room for one more, and your arrival is rarely as noticed as you fear.', 9, 34, 20, 0),
  ('rng_approaching_35', 'trk_approaching', 'Reach out to someone you admire from afar', 'Send a sincere message to a person you look up to, telling them what you appreciate.', 'Honest admiration is a gift, and people remember those who offer it.', 9, 35, 25, 0),
  ('rng_approaching_36', 'trk_approaching', 'Ask someone to meet up again after a first chat', 'Follow up with someone you recently met and propose seeing each other again.', 'Following up shows you mean it, and that sincerity is rare and welcome.', 10, 36, 30, 0),
  ('rng_approaching_37', 'trk_approaching', 'Strike up a chat with a complete stranger anywhere', 'Begin a friendly conversation with a stranger in an everyday place, with no excuse needed.', 'You now have everything you need to connect with anyone, anywhere.', 10, 37, 25, 0),
  ('rng_approaching_38', 'trk_approaching', 'Tell someone you''d like to be friends', 'Let a person you enjoy know directly that you''d like to spend more time together.', 'Naming what you want is bold and kind, and it gives a friendship room to grow.', 10, 38, 30, 0),
  ('rng_approaching_39', 'trk_approaching', 'Work a room and meet several new people', 'At an event, set out to introduce yourself to three or more new people across the evening.', 'Each hello gets a little easier, and by the end the room feels like yours.', 10, 39, 40, 0),
  ('rng_approaching_40', 'trk_approaching', 'Ask out someone you find truly intimidating', 'Approach a person who genuinely makes you nervous and invite them to spend time together.', 'You''ve climbed every rung to reach this one, and you''re more ready than you feel.', 10, 40, 30, 0),
  ('rng_social_events_11', 'trk_social_events', 'Arrive early before the room fills up', 'Show up at the start when only a few people are there, and settle in before the crowd builds.', 'Easing in early lets you warm up slowly instead of walking into a full room.', 5, 11, 20, 0),
  ('rng_social_events_12', 'trk_social_events', 'Refill your drink and chat on the way', 'Walk to the drinks or snack table and exchange a few friendly words with whoever is there.', 'Small errands give you an easy, low-pressure reason to start a quick chat.', 5, 12, 15, 0),
  ('rng_social_events_13', 'trk_social_events', 'Join a group mid-conversation', 'Step into a group that''s already talking, listen for a moment, then add a small comment.', 'You''ll learn that most groups quietly make room for one more.', 6, 13, 30, 0),
  ('rng_social_events_14', 'trk_social_events', 'Give one person a genuine compliment', 'Tell someone one true, kind thing you noticed about them or their work.', 'A warm word is an easy opener that usually brightens both of you.', 6, 14, 10, 0),
  ('rng_social_events_15', 'trk_social_events', 'Mingle with three different groups', 'Over the event, move between three separate clusters of people instead of staying put.', 'Moving around shows you can flow through a room rather than anchor to one spot.', 6, 15, 45, 0),
  ('rng_social_events_16', 'trk_social_events', 'Join the group photo', 'Step in when a photo is being taken instead of slipping out of frame.', 'Letting yourself be seen and included is a quiet act of belonging.', 7, 16, 15, 0),
  ('rng_social_events_17', 'trk_social_events', 'Try a group activity or game', 'Join in a board game, quiz, or team activity rather than watching from the side.', 'Shared play takes the focus off you and onto the fun you''re having together.', 7, 17, 60, 0),
  ('rng_social_events_18', 'trk_social_events', 'Say a proper goodbye to three people', 'Before you leave, find three people and say goodbye instead of quietly slipping out.', 'Closing well leaves a warm impression and makes the next meeting easier.', 7, 18, 30, 0),
  ('rng_social_events_19', 'trk_social_events', 'Ask someone to swap contact details', 'With someone you enjoyed talking to, ask to exchange numbers or socials.', 'One small ask is how a single event can turn into a real friendship.', 7, 19, 30, 0),
  ('rng_social_events_20', 'trk_social_events', 'Stay until the event winds down', 'Let yourself stay through to the natural end instead of leaving at the first lull.', 'The quieter late hours are often where the easiest, realest conversations happen.', 7, 20, 90, 0),
  ('rng_social_events_21', 'trk_social_events', 'Be the one who suggests the plan', 'Propose where to go or what to do next, and let the group follow your idea.', 'Suggesting a plan shows your voice can shape a night, not just join it.', 7, 21, 60, 0),
  ('rng_social_events_22', 'trk_social_events', 'Speak up in a group conversation', 'Share an opinion or story to the whole group, not just the person beside you.', 'Taking the floor briefly proves the group is glad to hear from you.', 8, 22, 30, 0),
  ('rng_social_events_23', 'trk_social_events', 'Tell a joke or light story to the table', 'Offer one funny or lighthearted moment to the people around you and let it land.', 'Sharing a laugh, even an imperfect one, is how warmth spreads in a group.', 8, 23, 20, 0),
  ('rng_social_events_24', 'trk_social_events', 'Dance, even just a little', 'Step onto the floor and move for one song instead of watching from the edge.', 'Letting your body join in loosens the grip of self-consciousness.', 8, 24, 30, 0),
  ('rng_social_events_25', 'trk_social_events', 'Go to a party where you know one person', 'Accept an invite to a party where your only familiar face is the host or a single friend.', 'Most of the room will be new, and you''ll see you can still find your footing.', 8, 25, 120, 0),
  ('rng_social_events_26', 'trk_social_events', 'Attend a networking event', 'Go to a professional mixer and introduce yourself to at least two new people.', 'Practising small talk with strangers builds a skill that pays off everywhere.', 8, 26, 120, 0),
  ('rng_social_events_27', 'trk_social_events', 'Reconnect with someone you drifted from', 'Approach an old acquaintance at the event and pick the friendship back up.', 'Most people are quietly glad to be remembered and reached out to.', 8, 27, 30, 0),
  ('rng_social_events_28', 'trk_social_events', 'Bring a friend to a new group', 'Introduce a friend of yours into a social circle they don''t yet know.', 'Bridging two worlds shows how comfortable you''ve become moving between them.', 8, 28, 90, 0),
  ('rng_social_events_29', 'trk_social_events', 'Volunteer to help run the event', 'Offer to take on a small role like greeting, serving, or setting up.', 'A clear job gives you an easy place to stand and a reason to talk to everyone.', 8, 29, 60, 0),
  ('rng_social_events_30', 'trk_social_events', 'Go to a wedding or big celebration', 'Attend a large, lively event and stay through the main moments of the day.', 'Big celebrations are full of warmth, and you deserve to be part of them.', 9, 30, 120, 0),
  ('rng_social_events_31', 'trk_social_events', 'Sit at a table of strangers', 'Choose or accept a seat among people you don''t know and stay for the meal.', 'A shared table naturally turns strangers into easy conversation over time.', 9, 31, 90, 0),
  ('rng_social_events_32', 'trk_social_events', 'Make a short toast or thank-you', 'Stand and say a few warm words to the room to mark the occasion.', 'A brief, heartfelt toast shows your voice can hold a room kindly.', 9, 32, 30, 0),
  ('rng_social_events_33', 'trk_social_events', 'Commit to a weekly social group', 'Join a club or recurring meetup and show up for several weeks in a row.', 'Familiar faces each week turn fresh nerves into comfortable belonging.', 9, 33, 120, 0),
  ('rng_social_events_34', 'trk_social_events', 'Host a themed party', 'Plan and host a gathering with a theme, inviting a wider mix of people.', 'Setting the scene for others shows how far your confidence has grown.', 9, 34, 120, 0),
  ('rng_social_events_35', 'trk_social_events', 'Invite people who don''t know each other', 'Host a gathering that mixes friends from different parts of your life.', 'Bringing your worlds together is a quiet sign of how at ease you''ve become.', 9, 35, 120, 0),
  ('rng_social_events_36', 'trk_social_events', 'Attend a multi-day event or retreat', 'Go to a conference, camp, or retreat that spans more than one day of socializing.', 'Staying social over several days builds a deeper, steadier kind of ease.', 9, 36, 120, 0),
  ('rng_social_events_37', 'trk_social_events', 'Organize a group outing from scratch', 'Plan a trip or day out, invite the people, and lead the group on the day.', 'Carrying a whole plan from idea to reality shows real social leadership.', 10, 37, 120, 0),
  ('rng_social_events_38', 'trk_social_events', 'Throw a party with a guest list of 15+', 'Host a larger gathering and welcome more than fifteen guests through the night.', 'A full room of your own making is proof of how much you''ve grown.', 10, 38, 120, 0),
  ('rng_social_events_39', 'trk_social_events', 'Speak or perform in front of the group', 'Give a talk, sing, or present something to everyone at the event.', 'Holding the spotlight on purpose turns old fear into quiet pride.', 10, 39, 120, 0),
  ('rng_social_events_40', 'trk_social_events', 'Become the regular host of your circle', 'Take on the ongoing role of the person who plans and hosts your group''s events.', 'Being the one who brings people together is where shyness becomes connection.', 10, 40, 120, 0),
  ('rng_assertiveness_11', 'trk_assertiveness', 'Ask someone to let you finish speaking', 'When you get interrupted, calmly say "I''d like to finish my thought" and continue.', 'Your words deserve room, and reclaiming them gets easier each time you try.', 5, 11, 3, 0),
  ('rng_assertiveness_12', 'trk_assertiveness', 'Say no to a small request from your boss', 'Decline one minor extra task at work with a simple "I can''t take that on right now."', 'Saying no to authority once shows you that you can stay safe and respected while doing it.', 5, 12, 5, 0),
  ('rng_assertiveness_13', 'trk_assertiveness', 'Ask a friend to repay money they owe you', 'Send a friendly, direct message reminding someone about money they borrowed.', 'Asking for what you''re owed is fair, and most people simply appreciate the reminder.', 6, 13, 5, 0),
  ('rng_assertiveness_14', 'trk_assertiveness', 'Tell someone their joke didn''t sit right', 'Let a person know, gently, that a comment they made bothered you.', 'Naming what stings teaches people how to treat you, and that''s a kindness to both of you.', 6, 14, 4, 0),
  ('rng_assertiveness_15', 'trk_assertiveness', 'Decline a family obligation you dread', 'Politely opt out of one family commitment that drains you this week.', 'Choosing what you join is allowed, even with the people closest to you.', 6, 15, 5, 0),
  ('rng_assertiveness_16', 'trk_assertiveness', 'Restate your point after being talked over', 'When someone overrides you in a group, calmly repeat your idea once more.', 'Coming back to your point shows it mattered, and the room hears you the second time.', 6, 16, 5, 0),
  ('rng_assertiveness_17', 'trk_assertiveness', 'Hold your no when someone pushes back', 'After you decline something, repeat your no calmly instead of giving in to pressure.', 'Standing steady once proves your answer can hold, and that confidence stays with you.', 7, 17, 5, 0),
  ('rng_assertiveness_18', 'trk_assertiveness', 'Ask for credit for your work', 'Mention your contribution to a project out loud when it''s being discussed.', 'Letting your effort be seen is honest, not boastful, and your work deserves the light.', 7, 18, 6, 0),
  ('rng_assertiveness_19', 'trk_assertiveness', 'Speak up when someone cuts the line', 'Calmly tell a person who jumped ahead that you were next in line.', 'Quietly standing your ground in small moments builds the voice you''ll use in big ones.', 7, 19, 5, 0),
  ('rng_assertiveness_20', 'trk_assertiveness', 'Tell a friend a habit of theirs bothers you', 'Share with a close friend one recurring behavior that''s been affecting you.', 'Honest words spoken with care tend to bring people closer, not push them away.', 7, 20, 6, 0),
  ('rng_assertiveness_21', 'trk_assertiveness', 'Speak up for someone being talked over', 'When another person gets interrupted, say "I''d like to hear the rest of what they were saying."', 'Using your voice for someone else is a warm, powerful way to grow your own.', 7, 21, 8, 0),
  ('rng_assertiveness_22', 'trk_assertiveness', 'Ask your boss for clearer expectations', 'Tell a manager you need specifics, and ask directly for what would help you.', 'Asking for clarity is a strength, and good leaders respect someone who does.', 7, 22, 6, 0),
  ('rng_assertiveness_23', 'trk_assertiveness', 'Decline unpaid extra work', 'Tell someone that taking on more without fair recognition isn''t something you can do.', 'Valuing your time invites others to value it too, and that''s a fair thing to ask.', 8, 23, 7, 0),
  ('rng_assertiveness_24', 'trk_assertiveness', 'Address a comment that felt disrespectful', 'Tell the person directly that the way they spoke to you didn''t feel okay.', 'Naming disrespect calmly is how you teach people the line, and you''re allowed to draw it.', 8, 24, 8, 0),
  ('rng_assertiveness_25', 'trk_assertiveness', 'Ask for a fair price or a discount', 'Request a better rate on a purchase or bill, and wait calmly for the answer.', 'Asking costs nothing, and a steady request is often met with a yes.', 8, 25, 10, 0),
  ('rng_assertiveness_26', 'trk_assertiveness', 'Hold a boundary with a family member', 'Restate a limit you''ve set with a relative, even when they push to change it.', 'Keeping a boundary with family is hard and brave, and it protects the love beneath it.', 8, 26, 10, 0),
  ('rng_assertiveness_27', 'trk_assertiveness', 'Tell someone you''ve changed your mind', 'Let a person know you''re no longer going along with something you''d agreed to.', 'You''re allowed to update your answer, and saying so honestly is its own kind of strength.', 8, 27, 10, 0),
  ('rng_assertiveness_28', 'trk_assertiveness', 'Disagree with someone more senior', 'Share a respectful but different view with a person who has more authority than you.', 'A calm, thoughtful disagreement shows you can stand on your own ideas.', 8, 28, 10, 0),
  ('rng_assertiveness_29', 'trk_assertiveness', 'Ask to be paid back for covering a cost', 'Tell someone clearly that you''d like them to cover their share of an expense.', 'Speaking up about money is normal and fair, and the discomfort fades fast once you do.', 8, 29, 12, 0),
  ('rng_assertiveness_30', 'trk_assertiveness', 'Say no to a guilt trip', 'Decline a request even when the other person tries to make you feel guilty.', 'Holding your choice through guilt shows you that your needs are allowed to matter too.', 9, 30, 12, 0),
  ('rng_assertiveness_31', 'trk_assertiveness', 'Bring up a problem with your manager', 'Raise one ongoing work issue directly with your boss and suggest a change.', 'Naming a problem to a leader is how things improve, and your perspective is worth hearing.', 9, 31, 15, 0),
  ('rng_assertiveness_32', 'trk_assertiveness', 'Ask for a raise or what you''re worth', 'Tell someone with authority that you''d like to be compensated more, and name a number.', 'Stating your value out loud is a skill, and you grow it the moment you ask.', 9, 32, 15, 0),
  ('rng_assertiveness_33', 'trk_assertiveness', 'Stand firm when someone raises their voice', 'Stay calm and keep your position when another person gets loud or heated.', 'Staying steady through someone''s heat shows you that you can hold your ground safely.', 9, 33, 15, 0),
  ('rng_assertiveness_34', 'trk_assertiveness', 'Name a pattern that keeps hurting you', 'Tell someone close that a repeated way they treat you needs to change.', 'Naming the pattern, not just the moment, is how real things finally shift.', 9, 34, 15, 0),
  ('rng_assertiveness_35', 'trk_assertiveness', 'Advocate for a fair outcome for someone else', 'Speak up to a person in charge on behalf of someone being treated unfairly.', 'Standing up for another person is courage in its kindest form.', 9, 35, 20, 0),
  ('rng_assertiveness_36', 'trk_assertiveness', 'Have a hard conversation you''ve been avoiding', 'Sit down with someone and finally say the thing you''ve been putting off.', 'The dread is almost always heavier than the conversation, and relief waits on the other side.', 10, 36, 20, 0),
  ('rng_assertiveness_37', 'trk_assertiveness', 'Hold your boundary through real pushback', 'Keep your limit in place even as someone repeatedly tries to talk you out of it.', 'Every time you hold firm, you prove to yourself that your no can survive pressure.', 10, 37, 20, 0),
  ('rng_assertiveness_38', 'trk_assertiveness', 'End a relationship that isn''t working', 'Tell someone clearly that you''re stepping back from a connection that no longer fits.', 'Closing a door with honesty makes room for the people who truly belong in your life.', 10, 38, 25, 0),
  ('rng_assertiveness_39', 'trk_assertiveness', 'Negotiate a high-stakes outcome you care about', 'Sit down for an important negotiation and ask firmly for what you truly want.', 'Asking fully for what matters most is the boldest form of believing you deserve it.', 10, 39, 30, 0),
  ('rng_assertiveness_40', 'trk_assertiveness', 'Confront ongoing unfair treatment head-on', 'Directly address a person or situation that has been treating you unfairly over time.', 'Facing what''s been wearing on you is how you reclaim your footing, and you don''t have to do it perfectly.', 10, 40, 30, 0),
  ('rng_visibility_11', 'trk_visibility', 'Add your real name and photo to a profile', 'Update one online profile to show your real name and a clear photo of your face.', 'Letting people see who you really are is a quiet act of courage.', 5, 11, 10, 0),
  ('rng_visibility_12', 'trk_visibility', 'Comment publicly on someone''s post', 'Leave a thoughtful, visible comment on a public post where others will see your name.', 'Adding your voice in public, even briefly, helps it feel safer over time.', 5, 12, 5, 0),
  ('rng_visibility_13', 'trk_visibility', 'Share a finished piece of your work online', 'Post something you made, like writing, art, or a project, where people can react to it.', 'Showing your effort to the world lets your work be seen on its own terms.', 6, 13, 15, 0),
  ('rng_visibility_14', 'trk_visibility', 'Raise your hand to volunteer for something', 'Offer to take on a visible task or role in a group where others will notice.', 'Choosing to be seen, rather than waiting to be picked, builds real confidence.', 6, 14, 10, 0),
  ('rng_visibility_15', 'trk_visibility', 'Wear something boldly your own', 'Step out in an outfit or item that clearly reflects your taste and stands out a little.', 'Letting your style speak for you is a gentle way to be visible on purpose.', 6, 15, 5, 0),
  ('rng_visibility_16', 'trk_visibility', 'Accept public praise with a simple thank you', 'When someone compliments you in front of others, just smile and say thank you.', 'Receiving praise openly lets you take up the space you''ve earned.', 6, 16, 3, 0),
  ('rng_visibility_17', 'trk_visibility', 'Post a photo with your face clearly shown', 'Share a recent photo where your face is the clear focus, not hidden or cropped.', 'Being plainly seen, as you are, is a meaningful step toward feeling at ease.', 7, 17, 10, 0),
  ('rng_visibility_18', 'trk_visibility', 'Ask a question in a meeting or class', 'Speak up with a genuine question in a group setting where everyone can hear you.', 'Your curiosity is worth voicing, and others often wonder the same thing.', 7, 18, 15, 0),
  ('rng_visibility_19', 'trk_visibility', 'Share your opinion in a group discussion', 'Offer your honest view in a conversation, even if it differs from the others.', 'Your perspective adds something, and it''s okay to be heard.', 7, 19, 15, 0),
  ('rng_visibility_20', 'trk_visibility', 'Record and post a short video of yourself talking', 'Film yourself speaking for a minute about something you care about and share it.', 'Letting people hear and see you speak is a brave way to show up fully.', 7, 20, 20, 0),
  ('rng_visibility_21', 'trk_visibility', 'Put your name on something you created', 'Publicly credit yourself as the author or maker of something you''ve shared.', 'Owning your work by name lets you stand proudly behind it.', 7, 21, 10, 0),
  ('rng_visibility_22', 'trk_visibility', 'Give a short toast or few words to a group', 'Stand and say a brief, heartfelt few sentences to a gathering of people.', 'Holding everyone''s attention for a moment shows you can be the focus and be okay.', 8, 22, 15, 0),
  ('rng_visibility_23', 'trk_visibility', 'Go live or do a real-time video call with a group', 'Turn your camera on and speak in a live video where people can see you in the moment.', 'Being seen in real time, unedited, helps you trust that you''re enough as you are.', 8, 23, 20, 0),
  ('rng_visibility_24', 'trk_visibility', 'Respectfully disagree with someone in public', 'Voice a different view to someone in front of others, kindly and clearly.', 'Standing by your view in the open shows you can be seen and still be respected.', 8, 24, 15, 0),
  ('rng_visibility_25', 'trk_visibility', 'Share a personal story with a real audience', 'Tell a meaningful story from your own life to a group who''s listening to you.', 'Letting people into your experience is a deep and brave kind of visibility.', 8, 25, 20, 0),
  ('rng_visibility_26', 'trk_visibility', 'Post about something you feel strongly about', 'Share a heartfelt opinion publicly on a topic that matters to you.', 'Letting your values be seen connects you with people who feel the same.', 8, 26, 15, 0),
  ('rng_visibility_27', 'trk_visibility', 'Respond calmly to a piece of criticism', 'When someone critiques you publicly, reply with a steady, gracious response.', 'Staying composed under critique shows yourself that you can handle being judged.', 8, 27, 10, 0),
  ('rng_visibility_28', 'trk_visibility', 'Lead a short part of a meeting or session', 'Take charge of presenting or guiding one segment while others follow along.', 'Stepping into a leading role lets you practice being seen as capable.', 9, 28, 25, 0),
  ('rng_visibility_29', 'trk_visibility', 'Perform a creative act in front of others', 'Sing, play, read, or perform something you prepared for a watching audience.', 'Sharing your creativity live is a generous and courageous way to be seen.', 9, 29, 20, 0),
  ('rng_visibility_30', 'trk_visibility', 'Publish a piece of writing under your name', 'Put out an article, post, or essay publicly with your name attached as the author.', 'Standing as the named voice behind your ideas is a strong, lasting step.', 9, 30, 20, 0),
  ('rng_visibility_31', 'trk_visibility', 'Let yourself be filmed or photographed for others', 'Agree to be recorded or photographed for something that others will see.', 'Allowing your image to be shared shows you can be visible without hiding.', 9, 31, 15, 0),
  ('rng_visibility_32', 'trk_visibility', 'Ask for feedback on your work in public', 'Invite open critique of something you made, where others can read the responses.', 'Inviting judgment on purpose helps it lose its grip on you.', 9, 32, 25, 0),
  ('rng_visibility_33', 'trk_visibility', 'Speak up for a view that may get pushback', 'State an unpopular but honest opinion publicly, knowing some may disagree.', 'Being seen holding your ground is a powerful kind of self-trust.', 9, 33, 20, 0),
  ('rng_visibility_34', 'trk_visibility', 'Host or introduce an event or gathering', 'Welcome a group and guide the start of an event as the visible host.', 'Setting the tone as the one in front shows you can hold the room.', 9, 34, 25, 0),
  ('rng_visibility_35', 'trk_visibility', 'Give a full presentation to an audience', 'Deliver a prepared talk where you are the sole focus for several minutes.', 'Holding center stage from start to finish proves how far you''ve come.', 10, 35, 30, 0),
  ('rng_visibility_36', 'trk_visibility', 'Go live to an audience you don''t know', 'Stream or broadcast yourself live to strangers, speaking openly in real time.', 'Being seen by unfamiliar eyes, unscripted, is a bold leap worth celebrating.', 10, 36, 20, 0),
  ('rng_visibility_37', 'trk_visibility', 'Be the named face of a project or cause', 'Publicly attach yourself as the lead or spokesperson for something you believe in.', 'Letting your name and face represent something shows deep confidence in yourself.', 10, 37, 25, 0),
  ('rng_visibility_38', 'trk_visibility', 'Share something vulnerable with a wide audience', 'Post or speak openly about a personal struggle or truth to many people.', 'Showing your real self, even the tender parts, is the bravest visibility of all.', 10, 38, 20, 0),
  ('rng_visibility_39', 'trk_visibility', 'Stand by your work as people openly judge it', 'Present something you made to an audience and stay present through their reactions.', 'Remaining grounded while others judge your work shows real inner steadiness.', 10, 39, 25, 0),
  ('rng_visibility_40', 'trk_visibility', 'Put yourself forward for a visible opportunity', 'Apply, audition, or volunteer for a role that will place you clearly in the spotlight.', 'Choosing the spotlight on purpose is the fullest expression of being seen.', 10, 40, 30, 0),
  ('rng_pressure_11', 'trk_pressure', 'Restate someone''s point back to them live', 'In a conversation, summarize what the other person just said out loud before you reply.', 'Reflecting back under live attention builds calm, focused presence.', 5, 11, 5, 0),
  ('rng_pressure_12', 'trk_pressure', 'Demo something you made to one person', 'Walk a single person through something you built or did, step by step.', 'Showing your work to one friendly viewer is a gentle way to practice.', 5, 12, 10, 0),
  ('rng_pressure_13', 'trk_pressure', 'Disagree out loud in a small group', 'When you see it differently, say so calmly in front of two or three people.', 'Voicing a different view in the moment gets easier each time you try.', 6, 13, 5, 0),
  ('rng_pressure_14', 'trk_pressure', 'Say "I don''t know" without backpedaling', 'When you''re asked something you can''t answer, say you don''t know and stop there.', 'Sitting calmly with not knowing is a quiet kind of confidence.', 6, 14, 3, 0),
  ('rng_pressure_15', 'trk_pressure', 'Answer a few questions about your work', 'Share something you did, then take three or four follow-up questions on the spot.', 'Each answered question proves you can think while being watched.', 6, 15, 10, 0),
  ('rng_pressure_16', 'trk_pressure', 'Defend a choice when someone pushes back', 'When someone questions a decision you made, calmly explain your reasoning.', 'Holding your ground gently shows your view can stand up to a little pressure.', 7, 16, 10, 0),
  ('rng_pressure_17', 'trk_pressure', 'Run a short practice interview', 'Ask a friend to fire a few interview-style questions and answer them in real time.', 'Rehearsing pressure on purpose makes the real thing feel familiar.', 7, 17, 15, 0),
  ('rng_pressure_18', 'trk_pressure', 'Recover out loud from a small slip', 'After you stumble or misspeak in front of others, name it lightly and carry on.', 'Recovering gracefully matters far more than never slipping.', 7, 18, 5, 0),
  ('rng_pressure_19', 'trk_pressure', 'Give live feedback to someone''s face', 'Offer one honest, kind piece of feedback to a person directly, in the moment.', 'Speaking a real opinion to someone live builds steady, honest nerve.', 7, 19, 10, 0),
  ('rng_pressure_20', 'trk_pressure', 'Present briefly to a small audience', 'Stand up and talk through one idea for a few minutes to a handful of people.', 'A short talk to a few faces is a real, manageable step into the spotlight.', 8, 20, 15, 0),
  ('rng_pressure_21', 'trk_pressure', 'Take a hard question without deflecting', 'When someone asks something pointed, answer it directly instead of changing the subject.', 'Facing the tough one head-on shows yourself you can handle it.', 7, 21, 10, 0),
  ('rng_pressure_22', 'trk_pressure', 'Lead a group through a quick decision', 'Guide a few people to choose between options and land on one within a set time.', 'Steering a group under a clock builds calm, decisive leadership.', 8, 22, 10, 0),
  ('rng_pressure_23', 'trk_pressure', 'Speak up first in a tense moment', 'When a silence falls and everyone''s unsure, be the one who talks first.', 'Breaking a heavy silence shows you can act when others hesitate.', 8, 23, 5, 0),
  ('rng_pressure_24', 'trk_pressure', 'Explain a topic you half-know live', 'Teach something you only partly understand to someone, thinking aloud as you go.', 'Working it out in real time is how real understanding gets built.', 8, 24, 15, 0),
  ('rng_pressure_25', 'trk_pressure', 'Do a mock interview with a stranger', 'Have someone you don''t know well run you through a practice interview.', 'Unfamiliar faces raise the stakes a little, and you can meet them.', 8, 25, 20, 0),
  ('rng_pressure_26', 'trk_pressure', 'Hold your point against two people', 'When two people disagree with you at once, calmly restate and stand by your view.', 'Staying steady when outnumbered builds real composure under pressure.', 8, 26, 10, 0),
  ('rng_pressure_27', 'trk_pressure', 'Present and then take open questions', 'Give a short talk to a group, then invite any questions and answer them live.', 'Speaking plus unscripted Q&A is the full pressure rehearsal, and it''s learnable.', 9, 27, 15, 0),
  ('rng_pressure_28', 'trk_pressure', 'Make a real-time call others are watching', 'With people waiting on you, make a meaningful decision and own it out loud.', 'Deciding under watchful eyes shows your judgment holds up live.', 9, 28, 10, 0),
  ('rng_pressure_29', 'trk_pressure', 'Improvise when your plan falls apart', 'When something goes off-script in front of others, adjust on the spot and keep going.', 'Bending instead of freezing is a skill you can grow with practice.', 9, 29, 15, 0),
  ('rng_pressure_30', 'trk_pressure', 'Defend your work to a skeptical person', 'Walk a doubtful person through your work and answer their challenges calmly.', 'Standing behind your work under scrutiny is deeply steadying once you do it.', 9, 30, 20, 0),
  ('rng_pressure_31', 'trk_pressure', 'Answer rapid-fire questions in a row', 'Let someone ask you several quick questions back to back and answer each one.', 'Keeping pace under quick fire trains fast, calm thinking.', 9, 31, 10, 0),
  ('rng_pressure_32', 'trk_pressure', 'Lead a meeting while being evaluated', 'Run a short meeting knowing someone there is assessing how you do.', 'Leading while watched closely is a stretch you''re ready to meet.', 9, 32, 20, 0),
  ('rng_pressure_33', 'trk_pressure', 'Enter a small friendly competition', 'Join a low-stakes contest or game where others can see how you perform.', 'Competing for fun lets you feel pressure with the safety net of play.', 9, 33, 15, 0),
  ('rng_pressure_34', 'trk_pressure', 'Sit a real interview or assessment', 'Take part in an actual interview, audition, or test that genuinely matters to you.', 'Real stakes are the truest practice, and you''re more ready than you feel.', 10, 34, 20, 0),
  ('rng_pressure_35', 'trk_pressure', 'Field pushback from a whole group', 'Share a view to several people and respond to their challenges as they come.', 'Holding steady against a room is a powerful thing to discover you can do.', 9, 35, 15, 0),
  ('rng_pressure_36', 'trk_pressure', 'Demo something live that could fail', 'Show a real demo in front of people, knowing it might not go perfectly.', 'Performing with real risk of a hitch builds the deepest kind of nerve.', 10, 36, 20, 0),
  ('rng_pressure_37', 'trk_pressure', 'Recover from a public mistake gracefully', 'After something visibly goes wrong in front of others, steady yourself and continue.', 'Coming back from a public stumble proves a mistake is never the end.', 10, 37, 15, 0),
  ('rng_pressure_38', 'trk_pressure', 'Lead a high-stakes group under a clock', 'Guide a group through a task that matters, with limited time and people watching.', 'Pulling a team through real pressure shows just how much you can carry.', 10, 38, 25, 0),
  ('rng_pressure_39', 'trk_pressure', 'Have a tough conversation you can''t rehearse', 'Hold an important, unpredictable conversation and respond honestly as it unfolds.', 'Meeting an unscripted, high-stakes talk head-on is real, lasting growth.', 10, 39, 20, 0),
  ('rng_pressure_40', 'trk_pressure', 'Perform or speak to a full audience', 'Speak, present, or perform in front of a sizeable audience from start to finish.', 'Standing fully in the spotlight is the summit, and every rung has led here.', 10, 40, 30, 0)
